/**
 * Analytics data models for the dashboard API.
 *
 * These interfaces define the shape of analytics data at every layer:
 * - Query parameters (what the caller asks for)
 * - Domain types (what the service computes)
 * - Response types (what the API returns)
 */

// ---------------------------------------------------------------------------
// Query / filter types
// ---------------------------------------------------------------------------

/** Supported time range presets for analytics queries. */
export type TimeRange = '24h' | '7d' | '30d' | '90d' | 'custom';

/** Granularity of time-series buckets. */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/** The category of metric being requested. */
export type MetricType = 'orders' | 'revenue' | 'users' | 'products';

/** Filters common to most analytics endpoints. */
export interface AnalyticsQuery {
  /** Pre-defined range shortcut. */
  timeRange: TimeRange;
  /** Required when timeRange is 'custom'. ISO-8601 date string. */
  startDate?: string;
  /** Required when timeRange is 'custom'. ISO-8601 date string. */
  endDate?: string;
  /** Bucket size for time-series data. Defaults to 'day'. */
  granularity?: TimeGranularity;
}

/** Filters specific to the metrics endpoint. */
export interface MetricQuery extends AnalyticsQuery {
  metricType: MetricType;
}

// ---------------------------------------------------------------------------
// Time-series primitives
// ---------------------------------------------------------------------------

/** A single data point in a time series. */
export interface TimeSeriesPoint {
  /** ISO-8601 timestamp marking the start of this bucket. */
  timestamp: string;
  /** The aggregated value for this bucket. */
  value: number;
}

/** A named time series (e.g. "revenue" or "new-users"). */
export interface TimeSeries {
  /** Machine-readable key, e.g. 'revenue', 'order_count'. */
  metric: string;
  /** Human-readable label for display. */
  label: string;
  /** Ordered list of data points. */
  points: TimeSeriesPoint[];
}

// ---------------------------------------------------------------------------
// Metric summaries
// ---------------------------------------------------------------------------

/** Summary card for a single KPI on the dashboard. */
export interface MetricSummary {
  /** Which metric this summarises. */
  metric: MetricType;
  /** Human-readable label. */
  label: string;
  /** Current value for the selected period. */
  currentValue: number;
  /** Value for the previous equivalent period (for comparison). */
  previousValue: number;
  /** Percentage change: ((current - previous) / previous) * 100. */
  changePercent: number;
  /** Positive = good, negative = bad, neutral = informational. */
  trend: 'up' | 'down' | 'flat';
}

// ---------------------------------------------------------------------------
// Top-products report
// ---------------------------------------------------------------------------

/** A row in the top-products leaderboard. */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
  orderCount: number;
}

// ---------------------------------------------------------------------------
// Composite response types
// ---------------------------------------------------------------------------

/** Full dashboard payload returned by GET /api/analytics/dashboard. */
export interface DashboardData {
  /** High-level KPI cards. */
  summaries: MetricSummary[];
  /** Revenue time series for the sparkline chart. */
  revenueTimeSeries: TimeSeries;
  /** Order-count time series for the sparkline chart. */
  orderTimeSeries: TimeSeries;
  /** Top 5 products by revenue. */
  topProducts: TopProduct[];
  /** ISO-8601 timestamp of when this snapshot was computed. */
  generatedAt: string;
}

/** Response for GET /api/analytics/metrics/:type. */
export interface MetricDetail {
  summary: MetricSummary;
  timeSeries: TimeSeries;
  generatedAt: string;
}

// ---------------------------------------------------------------------------
// Generic API envelope (thin wrapper so every response is consistent)
// ---------------------------------------------------------------------------

/** Standard analytics API response wrapper. */
export interface AnalyticsResponse<T> {
  success: boolean;
  data: T;
  query: AnalyticsQuery;
}

import { OrderRepository } from '../repositories/order.repository.js';
import { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricDetail,
  MetricSummary,
  MetricType,
  TimeSeries,
  TopProduct,
} from '../models/analytics.js';

/**
 * Aggregation service that computes analytics from order and user data.
 *
 * ## Design notes for implementers
 *
 * This service is the single place where raw repository data is transformed
 * into analytics-ready structures.  Each public method corresponds to one API
 * route (see `src/routes/analytics.routes.ts`).
 *
 * ### Aggregation strategy
 * 1. **Read** — pull the minimal set of entities from repositories using
 *    date-range predicates.  Prefer `findAll(predicate)` with a date filter
 *    over fetching everything.
 * 2. **Bucket** — group entities into time-series buckets based on the
 *    requested `granularity`.  Use `resolveTimeRange()` to turn a `TimeRange`
 *    shortcut into concrete `{ start, end }` dates.
 * 3. **Reduce** — compute the aggregate value for each bucket (sum, count,
 *    average, etc.).
 * 4. **Compare** — for KPI summaries, repeat steps 1-3 for the *previous*
 *    equivalent period and compute the percentage change.
 *
 * ### Performance considerations
 * The in-memory database makes full scans cheap today.  If this moves to a
 * real datastore, consider:
 * - Pre-aggregated materialised views for dashboard summaries.
 * - Caching layer (TTL ~60 s) in front of `getDashboard()`.
 * - Streaming aggregation for time-series with many buckets.
 */
export class AnalyticsService {
  private readonly logger: Logger;

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {
    this.logger = new Logger('AnalyticsService');
  }

  // -------------------------------------------------------------------------
  // Public API — one method per route
  // -------------------------------------------------------------------------

  /**
   * Returns the full dashboard payload (summaries + sparklines + top products).
   *
   * Route: GET /api/analytics/dashboard
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Computing dashboard for range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);

    const summaries = await this.computeAllSummaries(start, end);
    const revenueTimeSeries = this.buildTimeSeries('revenue', 'Revenue', start, end, query);
    const orderTimeSeries = this.buildTimeSeries('order_count', 'Orders', start, end, query);
    const topProducts = this.computeTopProducts(start, end, 5);

    return {
      summaries,
      revenueTimeSeries,
      orderTimeSeries,
      topProducts,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Returns detailed data for a single metric type.
   *
   * Route: GET /api/analytics/metrics/:type
   */
  async getMetricDetail(metricType: MetricType, query: AnalyticsQuery): Promise<MetricDetail> {
    this.logger.info(`Computing metric detail for type=${metricType}, range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);

    const summary = this.computeSummary(metricType, start, end);
    const timeSeries = this.buildTimeSeries(metricType, metricType, start, end, query);

    return {
      summary,
      timeSeries,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Returns top products by revenue for the given time range.
   *
   * Route: GET /api/analytics/top-products
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProduct[]> {
    this.logger.info(`Computing top products, limit=${limit}, range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);
    return this.computeTopProducts(start, end, limit);
  }

  // -------------------------------------------------------------------------
  // Private helpers — TODO: implement in Session 2/3
  // -------------------------------------------------------------------------

  /**
   * Compute KPI summaries for every metric type.
   *
   * Implementation guide:
   * - Iterate over all MetricType values.
   * - For each, call `computeSummary()`.
   */
  private async computeAllSummaries(start: Date, end: Date): Promise<MetricSummary[]> {
    const types: MetricType[] = ['orders', 'revenue', 'users', 'products'];
    return types.map((type) => this.computeSummary(type, start, end));
  }

  /**
   * Compute a single KPI summary with period-over-period comparison.
   *
   * Implementation guide:
   * - Query the repository for entities within [start, end].
   * - Compute the current-period value (count, sum, etc.).
   * - Compute the previous-period value using `previousPeriod(start, end)`.
   * - Calculate changePercent and trend.
   */
  private computeSummary(metricType: MetricType, _start: Date, _end: Date): MetricSummary {
    // TODO: replace with real aggregation in Session 2
    return {
      metric: metricType,
      label: metricTypeLabel(metricType),
      currentValue: 0,
      previousValue: 0,
      changePercent: 0,
      trend: 'flat',
    };
  }

  /**
   * Build a time series for a given metric over [start, end].
   *
   * Implementation guide:
   * - Determine bucket boundaries from granularity (or default based on range).
   * - For each bucket, query and aggregate the relevant value.
   * - Return a `TimeSeries` with one `TimeSeriesPoint` per bucket.
   */
  private buildTimeSeries(
    metric: string,
    label: string,
    _start: Date,
    _end: Date,
    _query: AnalyticsQuery,
  ): TimeSeries {
    // TODO: replace with real bucketing in Session 2
    return {
      metric,
      label,
      points: [],
    };
  }

  /**
   * Compute the top N products by revenue within [start, end].
   *
   * Implementation guide:
   * - Fetch all orders in the date range.
   * - Flatten order items.
   * - Group by productId, sum quantity and revenue, count distinct orders.
   * - Sort descending by totalRevenue, take the top `limit`.
   */
  private computeTopProducts(_start: Date, _end: Date, _limit: number): TopProduct[] {
    // TODO: replace with real aggregation in Session 3
    return [];
  }
}

// ---------------------------------------------------------------------------
// Pure utility functions
// ---------------------------------------------------------------------------

/** Resolve a `TimeRange` shortcut + optional custom dates into concrete dates. */
export function resolveTimeRange(query: AnalyticsQuery): { start: Date; end: Date } {
  const now = new Date();
  const end = new Date(now);

  switch (query.timeRange) {
    case '24h':
      return { start: new Date(now.getTime() - 24 * 60 * 60 * 1000), end };
    case '7d':
      return { start: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000), end };
    case '30d':
      return { start: new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000), end };
    case '90d':
      return { start: new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000), end };
    case 'custom': {
      if (!query.startDate || !query.endDate) {
        throw new Error('startDate and endDate are required when timeRange is "custom"');
      }
      return { start: new Date(query.startDate), end: new Date(query.endDate) };
    }
  }
}

/** Map MetricType to a human-readable label. */
function metricTypeLabel(type: MetricType): string {
  const labels: Record<MetricType, string> = {
    orders: 'Total Orders',
    revenue: 'Total Revenue',
    users: 'Active Users',
    products: 'Products Sold',
  };
  return labels[type];
}

import { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  AnalyticsResponse,
  DashboardData,
  MetricDetail,
  MetricType,
  TimeRange,
  TopProduct,
} from '../models/analytics.js';

// ---------------------------------------------------------------------------
// Route-handler types
// ---------------------------------------------------------------------------

/**
 * Framework-agnostic request representation.
 *
 * Handlers receive this instead of an Express/Koa/Hono-specific request so
 * the analytics routes can be wired into any HTTP framework via a thin adapter.
 */
export interface RouteRequest {
  params: Record<string, string>;
  query: Record<string, string>;
}

/** Framework-agnostic response representation. */
export interface RouteResponse<T> {
  status: number;
  body: T;
}

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

const VALID_TIME_RANGES: TimeRange[] = ['24h', '7d', '30d', '90d', 'custom'];
const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'products'];

/** Parse and validate common analytics query parameters. */
function parseAnalyticsQuery(raw: Record<string, string>): AnalyticsQuery {
  const timeRange = (raw['timeRange'] ?? '30d') as TimeRange;
  if (!VALID_TIME_RANGES.includes(timeRange)) {
    throw new ValidationError(`Invalid timeRange "${timeRange}". Must be one of: ${VALID_TIME_RANGES.join(', ')}`);
  }

  if (timeRange === 'custom' && (!raw['startDate'] || !raw['endDate'])) {
    throw new ValidationError('startDate and endDate query params are required when timeRange is "custom"');
  }

  return {
    timeRange,
    startDate: raw['startDate'],
    endDate: raw['endDate'],
    granularity: raw['granularity'] as AnalyticsQuery['granularity'],
  };
}

/** Typed validation error so callers can distinguish bad input from server errors. */
export class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}

// ---------------------------------------------------------------------------
// Route handler factory
// ---------------------------------------------------------------------------

/**
 * Creates the set of analytics route handlers.
 *
 * ## Route table
 *
 * | Method | Path                          | Handler              | Description                          |
 * |--------|-------------------------------|----------------------|--------------------------------------|
 * | GET    | /api/analytics/dashboard      | getDashboard         | Full dashboard (summaries + charts)  |
 * | GET    | /api/analytics/metrics/:type  | getMetricDetail      | Single metric detail + time series   |
 * | GET    | /api/analytics/top-products   | getTopProducts       | Top products leaderboard             |
 *
 * ## Wiring example (Express-like)
 * ```ts
 * const handlers = createAnalyticsHandlers(analyticsService);
 * app.get('/api/analytics/dashboard', adapt(handlers.getDashboard));
 * app.get('/api/analytics/metrics/:type', adapt(handlers.getMetricDetail));
 * app.get('/api/analytics/top-products', adapt(handlers.getTopProducts));
 * ```
 */
export function createAnalyticsHandlers(service: AnalyticsService) {
  return {
    /**
     * GET /api/analytics/dashboard?timeRange=30d[&granularity=day]
     *
     * Returns the composite dashboard payload.
     */
    async getDashboard(req: RouteRequest): Promise<RouteResponse<AnalyticsResponse<DashboardData>>> {
      const query = parseAnalyticsQuery(req.query);
      const data = await service.getDashboard(query);

      return {
        status: 200,
        body: { success: true, data, query },
      };
    },

    /**
     * GET /api/analytics/metrics/:type?timeRange=30d
     *
     * `:type` must be one of: orders, revenue, users, products.
     */
    async getMetricDetail(req: RouteRequest): Promise<RouteResponse<AnalyticsResponse<MetricDetail>>> {
      const metricType = req.params['type'] as MetricType;
      if (!VALID_METRIC_TYPES.includes(metricType)) {
        throw new ValidationError(
          `Invalid metric type "${metricType}". Must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
        );
      }

      const query = parseAnalyticsQuery(req.query);
      const data = await service.getMetricDetail(metricType, query);

      return {
        status: 200,
        body: { success: true, data, query },
      };
    },

    /**
     * GET /api/analytics/top-products?timeRange=30d[&limit=10]
     */
    async getTopProducts(req: RouteRequest): Promise<RouteResponse<AnalyticsResponse<TopProduct[]>>> {
      const query = parseAnalyticsQuery(req.query);
      const limit = Math.min(Math.max(parseInt(req.query['limit'] ?? '10', 10) || 10, 1), 100);
      const data = await service.getTopProducts(query, limit);

      return {
        status: 200,
        body: { success: true, data, query },
      };
    },
  };
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService, resolveTimeRange } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // -----------------------------------------------------------------------
  // resolveTimeRange (pure function)
  // -----------------------------------------------------------------------

  describe('resolveTimeRange', () => {
    it('should resolve 24h range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '24h' });
      const diffMs = end.getTime() - start.getTime();
      // Allow 100ms tolerance for execution time
      expect(Math.abs(diffMs - 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve 7d range', () => {
      const { start, end } = resolveTimeRange({ timeRange: '7d' });
      const diffMs = end.getTime() - start.getTime();
      expect(Math.abs(diffMs - 7 * 24 * 60 * 60 * 1000)).toBeLessThan(100);
    });

    it('should resolve custom range', () => {
      const query: AnalyticsQuery = {
        timeRange: 'custom',
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-01-31T23:59:59Z',
      };
      const { start, end } = resolveTimeRange(query);
      expect(start.toISOString()).toBe('2026-01-01T00:00:00.000Z');
      expect(end.toISOString()).toBe('2026-01-31T23:59:59.000Z');
    });

    it('should throw on custom range without dates', () => {
      expect(() => resolveTimeRange({ timeRange: 'custom' })).toThrow(
        'startDate and endDate are required',
      );
    });
  });

  // -----------------------------------------------------------------------
  // getDashboard
  // -----------------------------------------------------------------------

  describe('getDashboard', () => {
    it('should return a well-shaped dashboard with empty data', async () => {
      const result = await service.getDashboard({ timeRange: '30d' });

      expect(result.summaries).toHaveLength(4);
      expect(result.summaries.map((s) => s.metric)).toEqual([
        'orders',
        'revenue',
        'users',
        'products',
      ]);
      expect(result.revenueTimeSeries.metric).toBe('revenue');
      expect(result.orderTimeSeries.metric).toBe('order_count');
      expect(result.topProducts).toEqual([]);
      expect(result.generatedAt).toBeTruthy();
    });
  });

  // -----------------------------------------------------------------------
  // getMetricDetail
  // -----------------------------------------------------------------------

  describe('getMetricDetail', () => {
    it('should return detail for a valid metric type', async () => {
      const result = await service.getMetricDetail('revenue', { timeRange: '7d' });

      expect(result.summary.metric).toBe('revenue');
      expect(result.summary.label).toBe('Total Revenue');
      expect(result.timeSeries).toBeDefined();
      expect(result.generatedAt).toBeTruthy();
    });
  });

  // -----------------------------------------------------------------------
  // getTopProducts
  // -----------------------------------------------------------------------

  describe('getTopProducts', () => {
    it('should return an empty array when no orders exist', async () => {
      const result = await service.getTopProducts({ timeRange: '30d' }, 5);
      expect(result).toEqual([]);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsHandlers, ValidationError } from '../../src/routes/analytics.routes.js';

describe('Analytics Route Handlers', () => {
  let handlers: ReturnType<typeof createAnalyticsHandlers>;

  beforeEach(() => {
    const db = new Database();
    const service = new AnalyticsService(
      new OrderRepository(db),
      new UserRepository(db),
    );
    handlers = createAnalyticsHandlers(service);
  });

  describe('getDashboard', () => {
    it('should return 200 with dashboard data', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: { timeRange: '30d' },
      });

      expect(res.status).toBe(200);
      expect(res.body.success).toBe(true);
      expect(res.body.data.summaries).toHaveLength(4);
      expect(res.body.query.timeRange).toBe('30d');
    });

    it('should default timeRange to 30d when omitted', async () => {
      const res = await handlers.getDashboard({
        params: {},
        query: {},
      });

      expect(res.body.query.timeRange).toBe('30d');
    });
  });

  describe('getMetricDetail', () => {
    it('should return 200 for valid metric type', async () => {
      const res = await handlers.getMetricDetail({
        params: { type: 'revenue' },
        query: { timeRange: '7d' },
      });

      expect(res.status).toBe(200);
      expect(res.body.data.summary.metric).toBe('revenue');
    });

    it('should throw ValidationError for invalid metric type', async () => {
      await expect(
        handlers.getMetricDetail({
          params: { type: 'invalid' },
          query: { timeRange: '7d' },
        }),
      ).rejects.toThrow(ValidationError);
    });
  });

  describe('getTopProducts', () => {
    it('should return 200 with top products', async () => {
      const res = await handlers.getTopProducts({
        params: {},
        query: { timeRange: '30d', limit: '5' },
      });

      expect(res.status).toBe(200);
      expect(res.body.success).toBe(true);
    });

    it('should throw ValidationError for invalid timeRange', async () => {
      await expect(
        handlers.getTopProducts({
          params: {},
          query: { timeRange: 'invalid' },
        }),
      ).rejects.toThrow(ValidationError);
    });
  });
});

