+// ---------------------------------------------------------------------------
+
+/** Summary card for a single KPI on the dashboard. */
+export interface MetricSummary {
+  /** Which metric this summarises. */
+  metric: MetricType;
+  /** Human-readable label. */
+  label: string;
+  /** Current value for the selected period. */
+  currentValue: number;
+  /** Value for the previous equivalent period (for comparison). */
+  previousValue: number;
+  /** Percentage change: ((current - previous) / previous) * 100. */
+  changePercent: number;
+  /** Positive = good, negative = bad, neutral = informational. */
+  trend: 'up' | 'down' | 'flat';
+}
+
+// ---------------------------------------------------------------------------
+// Top-products report
+// ---------------------------------------------------------------------------
+
+/** A row in the top-products leaderboard. */
+export interface TopProduct {
+  productId: string;
+  name: string;
+  totalQuantity: number;
+  totalRevenue: number;
+  orderCount: number;
+}
+
+// ---------------------------------------------------------------------------
+// Composite response types
+// ---------------------------------------------------------------------------
+
+/** Full dashboard payload returned by GET /api/analytics/dashboard. */
+export interface DashboardData {
+  /** High-level KPI cards. */
+  summaries: MetricSummary[];
+  /** Revenue time series for the sparkline chart. */
+  revenueTimeSeries: TimeSeries;
+  /** Order-count time series for the sparkline chart. */
+  orderTimeSeries: TimeSeries;
+  /** Top 5 products by revenue. */
+  topProducts: TopProduct[];
+  /** ISO-8601 timestamp of when this snapshot was computed. */
+  generatedAt: string;
+}
+
+/** Response for GET /api/analytics/metrics/:type. */
+export interface MetricDetail {
+  summary: MetricSummary;
+  timeSeries: TimeSeries;
+  generatedAt: string;
+}
+
+// ---------------------------------------------------------------------------
+// Generic API envelope (thin wrapper so every response is consistent)
+// ---------------------------------------------------------------------------
+
+/** Standard analytics API response wrapper. */
+export interface AnalyticsResponse<T> {
+  success: boolean;
+  data: T;
+  query: AnalyticsQuery;
+}

