+import { AnalyticsService, resolveTimeRange } from '../../src/services/analytics.service.js';
+import type { AnalyticsQuery } from '../../src/models/analytics.js';
+
+describe('AnalyticsService', () => {
+  let db: Database;
+  let orderRepo: OrderRepository;
+  let userRepo: UserRepository;
+  let service: AnalyticsService;
+
+  beforeEach(() => {
+    db = new Database();
+    orderRepo = new OrderRepository(db);
+    userRepo = new UserRepository(db);
+    service = new AnalyticsService(orderRepo, userRepo);
+  });
+
+  // -----------------------------------------------------------------------
+  // resolveTimeRange (pure function)
+  // -----------------------------------------------------------------------
+
+  describe('resolveTimeRange', () => {
+    it('should resolve 24h range', () => {
+      const { start, end } = resolveTimeRange({ timeRange: '24h' });
+      const diffMs = end.getTime() - start.getTime();
+      // Allow 100ms tolerance for execution time
+      expect(Math.abs(diffMs - 24 * 60 * 60 * 1000)).toBeLessThan(100);
+    });
+
+    it('should resolve 7d range', () => {
+      const { start, end } = resolveTimeRange({ timeRange: '7d' });
+      const diffMs = end.getTime() - start.getTime();
+      expect(Math.abs(diffMs - 7 * 24 * 60 * 60 * 1000)).toBeLessThan(100);
+    });
+
+    it('should resolve custom range', () => {
+      const query: AnalyticsQuery = {
+        timeRange: 'custom',
+        startDate: '2026-01-01T00:00:00Z',
+        endDate: '2026-01-31T23:59:59Z',
+      };
+      const { start, end } = resolveTimeRange(query);
+      expect(start.toISOString()).toBe('2026-01-01T00:00:00.000Z');
+      expect(end.toISOString()).toBe('2026-01-31T23:59:59.000Z');
+    });
+
+    it('should throw on custom range without dates', () => {
+      expect(() => resolveTimeRange({ timeRange: 'custom' })).toThrow(
+        'startDate and endDate are required',
+      );
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getDashboard
+  // -----------------------------------------------------------------------
+
+  describe('getDashboard', () => {
+    it('should return a well-shaped dashboard with empty data', async () => {
+      const result = await service.getDashboard({ timeRange: '30d' });
+
+      expect(result.summaries).toHaveLength(4);
+      expect(result.summaries.map((s) => s.metric)).toEqual([
+        'orders',
+        'revenue',
+        'users',
+        'products',
+      ]);
+      expect(result.revenueTimeSeries.metric).toBe('revenue');
+      expect(result.orderTimeSeries.metric).toBe('order_count');
+      expect(result.topProducts).toEqual([]);
+      expect(result.generatedAt).toBeTruthy();
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getMetricDetail
+  // -----------------------------------------------------------------------
+
+  describe('getMetricDetail', () => {
+    it('should return detail for a valid metric type', async () => {
+      const result = await service.getMetricDetail('revenue', { timeRange: '7d' });
+
+      expect(result.summary.metric).toBe('revenue');
+      expect(result.summary.label).toBe('Total Revenue');
+      expect(result.timeSeries).toBeDefined();
+      expect(result.generatedAt).toBeTruthy();
+    });
+  });
+
+  // -----------------------------------------------------------------------
+  // getTopProducts
+  // -----------------------------------------------------------------------
+
+  describe('getTopProducts', () => {
+    it('should return an empty array when no orders exist', async () => {
+      const result = await service.getTopProducts({ timeRange: '30d' }, 5);
+      expect(result).toEqual([]);
+    });
+  });
+});
